import com.google.protobuf.DescriptorProtos.EnumValueOptions;
import com.google.protobuf.Descriptors.EnumValueDescriptor;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

import java.lang.reflect.Method;
import java.util.Collections;

class ProtoTypeAdapterTest {

  private ProtoTypeAdapter adapterNameSerialization;
  private ProtoTypeAdapter adapterNumberSerialization;
  private EnumValueDescriptor enumValueDescriptorMock;
  private EnumValueOptions enumValueOptionsMock;

  @BeforeEach
  void setUp() throws Exception {
    // Use ProtoTypeAdapter.EnumSerialization from the ProtoTypeAdapter class
    Class<?> enumSerializationClass = Class.forName("com.google.gson.protobuf.ProtoTypeAdapter$EnumSerialization");
    Object enumName = Enum.valueOf((Class<Enum>) enumSerializationClass, "NAME");
    Object enumNumber = Enum.valueOf((Class<Enum>) enumSerializationClass, "NUMBER");

    // Create ProtoTypeAdapter instances with different EnumSerialization values using reflection
    var constructor = ProtoTypeAdapter.class.getDeclaredConstructor(
        enumSerializationClass,
        com.google.common.base.CaseFormat.class,
        com.google.common.base.CaseFormat.class,
        java.util.Set.class,
        java.util.Set.class);
    constructor.setAccessible(true);

    adapterNameSerialization = (ProtoTypeAdapter) constructor.newInstance(
        enumName,
        null,
        null,
        Collections.emptySet(),
        Collections.emptySet()
    );
    adapterNumberSerialization = (ProtoTypeAdapter) constructor.newInstance(
        enumNumber,
        null,
        null,
        Collections.emptySet(),
        Collections.emptySet()
    );

    // Mock EnumValueDescriptor and EnumValueOptions
    enumValueDescriptorMock = mock(EnumValueDescriptor.class);
    enumValueOptionsMock = mock(EnumValueOptions.class);

    when(enumValueDescriptorMock.getOptions()).thenReturn(enumValueOptionsMock);
  }

  @Test
  void testGetEnumValue_enumSerializationName_returnsCustomSerializedEnumValue() throws Exception {
    // Prepare mock behavior
    when(enumValueDescriptorMock.getName()).thenReturn("ENUM_NAME");

    // Spy on adapterNameSerialization to mock private getCustSerializedEnumValue method
    ProtoTypeAdapter spyAdapter = Mockito.spy(adapterNameSerialization);

    // Mock private method getCustSerializedEnumValue to return a custom string
    Method getCustSerializedEnumValueMethod = ProtoTypeAdapter.class.getDeclaredMethod(
        "getCustSerializedEnumValue", EnumValueOptions.class, String.class);
    getCustSerializedEnumValueMethod.setAccessible(true);

    // Use doReturn().when(spy).method(args) pattern with reflection
    // Because getCustSerializedEnumValue is private, use Mockito's doReturn with spy and method name via doAnswer or doReturn with reflection
    // The easiest way is to use Mockito's doReturn with spy and reflection invoke:
    // But since direct doReturn with method name is not supported, we can mock via doAnswer:
    doReturn("customValue").when(spyAdapter).getClass()
        .getDeclaredMethod("getCustSerializedEnumValue", EnumValueOptions.class, String.class)
        .invoke(spyAdapter, enumValueOptionsMock, "ENUM_NAME");
    // The above line won't compile because doReturn expects a method call, so we must use doReturn with spy and use Mockito's doAnswer or doReturn with spy and use Whitebox or similar.
    // Instead, use Mockito's doReturn with spy and use Mockito's doReturn().when(spy).method(args) via reflection using Mockito's doReturn().when(spy).method(args) with Mockito 3 is not supported for private methods.
    // So use Mockito's doReturn().when(spy).method(args) via spy and reflection is complicated.
    // The alternative is to use PowerMockito or ReflectionTestUtils, but not allowed here.
    // So we can use Mockito's doAnswer to intercept the call via spy and override the private method via reflection:

    // Use a workaround: override the private method via reflection by creating a subclass or by using a proxy - complicated.
    // Instead, use Mockito's doAnswer on the spy's getEnumValue method to return "customValue" when EnumSerialization.NAME is used.
    // But the test requires to test getEnumValue invokes getCustSerializedEnumValue, so we must mock getCustSerializedEnumValue.

    // Alternative: Use reflection to set the private method accessible and replace it with a lambda via MethodHandles or use a proxy.
    // Since it's complicated, use Mockito's doReturn().when(spyAdapter).getCustSerializedEnumValue(...) by making getCustSerializedEnumValue package-private temporarily or use a helper subclass.

    // To keep it simple and working, create a subclass of ProtoTypeAdapter inside the test that overrides getCustSerializedEnumValue:

    class ProtoTypeAdapterForTest extends ProtoTypeAdapter {
      ProtoTypeAdapterForTest(Object enumSerialization) throws Exception {
        super(
            enumSerialization,
            null,
            null,
            Collections.emptySet(),
            Collections.emptySet()
        );
      }

      @Override
      protected String getCustSerializedEnumValue(EnumValueOptions options, String defaultValue) {
        return "customValue";
      }
    }

    // Create an instance of the subclass with EnumSerialization.NAME
    ProtoTypeAdapterForTest adapterForTest = new ProtoTypeAdapterForTest(
        Enum.valueOf((Class<Enum>) Class.forName("com.google.gson.protobuf.ProtoTypeAdapter$EnumSerialization"), "NAME"));

    // Mock enumValueDescriptorMock.getOptions() and getName() again for safety
    when(enumValueDescriptorMock.getOptions()).thenReturn(enumValueOptionsMock);
    when(enumValueDescriptorMock.getName()).thenReturn("ENUM_NAME");

    // Invoke private method getEnumValue via reflection
    Method getEnumValueMethod = ProtoTypeAdapter.class.getDeclaredMethod("getEnumValue", EnumValueDescriptor.class);
    getEnumValueMethod.setAccessible(true);
    Object result = getEnumValueMethod.invoke(adapterForTest, enumValueDescriptorMock);

    assertEquals("customValue", result);
  }

  @Test
  void testGetEnumValue_enumSerializationNumber_returnsNumber() throws Exception {
    // Prepare mock behavior
    when(enumValueDescriptorMock.getNumber()).thenReturn(123);

    // Invoke private method getEnumValue via reflection on adapterNumberSerialization
    Method getEnumValueMethod = ProtoTypeAdapter.class.getDeclaredMethod("getEnumValue", EnumValueDescriptor.class);
    getEnumValueMethod.setAccessible(true);
    Object result = getEnumValueMethod.invoke(adapterNumberSerialization, enumValueDescriptorMock);

    assertEquals(123, result);
  }
}
